SELECT l.*, ste.site_nm AS site_nm, mem.member_nm AS member_nm, cd_ta.code_label AS action_cd_nm, cd_tt.code_label AS token_type_cd_nm FROM mbh_member_token_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN mb_member mem ON mem.member_id = l.member_id LEFT JOIN sy_code cd_ta ON cd_ta.code_grp = 'TOKEN_ACTION' AND cd_ta.code_value = l.action_cd LEFT JOIN sy_code cd_tt ON cd_tt.code_grp = 'TOKEN_TYPE' AND cd_tt.code_value = l.token_type_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT l.*, ste.site_nm AS site_nm, mem.member_nm AS member_nm, cd_ta.code_label AS action_cd_nm, cd_tt.code_label AS token_type_cd_nm FROM mbh_member_token_log l LEFT JOIN sy_site ste ON ste.site_id = l.site_id LEFT JOIN mb_member mem ON mem.member_id = l.member_id LEFT JOIN sy_code cd_ta ON cd_ta.code_grp = 'TOKEN_ACTION' AND cd_ta.code_value = l.action_cd LEFT JOIN sy_code cd_tt ON cd_tt.code_grp = 'TOKEN_TYPE' AND cd_tt.code_value = l.token_type_cd
ORDER BY l.log_id ASC ORDER BY l.log_id DESC ORDER BY l.reg_date ASC ORDER BY l.reg_date DESC ORDER BY l.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}
